/**
 * Maps an action name to a keyboard key.
 */
bool goud_input_map_action_key(struct GoudContextId context_id, const char *action_name, GoudKeyCode key);

/**
 * Returns `true` if the specified action is currently pressed.
 */
bool goud_input_action_pressed(struct GoudContextId context_id, const char *action_name);

/**
 * Returns `true` if the specified action was just pressed this frame.
 */
bool goud_input_action_just_pressed(struct GoudContextId context_id, const char *action_name);

/**
 * Returns `true` if the specified action was just released this frame.
 */
bool goud_input_action_just_released(struct GoudContextId context_id, const char *action_name);

/**
 * Returns `true` if the specified key is currently pressed.
 */
bool goud_input_key_pressed(struct GoudContextId context_id, GoudKeyCode key);

/**
 * Returns `true` if the specified key was just pressed this frame.
 */
bool goud_input_key_just_pressed(struct GoudContextId context_id, GoudKeyCode key);

/**
 * Returns `true` if the specified key was just released this frame.
 */
bool goud_input_key_just_released(struct GoudContextId context_id, GoudKeyCode key);

/**
 * Returns `true` if the specified mouse button is currently pressed.
 */
bool goud_input_mouse_button_pressed(struct GoudContextId context_id, GoudMouseButton button);

/**
 * Returns `true` if the specified mouse button was just pressed this frame.
 */
bool goud_input_mouse_button_just_pressed(struct GoudContextId context_id, GoudMouseButton button);

/**
 * Returns `true` if the specified mouse button was just released this frame.
 */
bool goud_input_mouse_button_just_released(struct GoudContextId context_id, GoudMouseButton button);

/**
 * Gets the current mouse position in screen coordinates.
 */
bool goud_input_get_mouse_position(struct GoudContextId context_id, float *out_x, float *out_y);

/**
 * Gets the mouse movement delta since the last frame.
 */
bool goud_input_get_mouse_delta(struct GoudContextId context_id, float *out_dx, float *out_dy);

/**
 * Gets the scroll wheel delta since the last frame.
 */
bool goud_input_get_scroll_delta(struct GoudContextId context_id, float *out_dx, float *out_dy);

/* === Audio === */

/**
 * Activates audio playback on platforms that require explicit initialization.
 */
int32_t goud_audio_activate(struct GoudContextId context_id);

/**
 * Stops audio playback for the given player ID.
 */
int32_t goud_audio_stop(struct GoudContextId context_id, uint64_t player_id);

/**
 * Pauses audio playback for the given player ID.
 */
int32_t goud_audio_pause(struct GoudContextId context_id, uint64_t player_id);

/**
 * Resumes audio playback for the given player ID.
 */
int32_t goud_audio_resume(struct GoudContextId context_id, uint64_t player_id);

/**
 * Stops all currently playing audio.
 */
int32_t goud_audio_stop_all(struct GoudContextId context_id);

/**
 * Sets the global audio volume.
 */
int32_t goud_audio_set_global_volume(struct GoudContextId context_id, float volume);

/**
 * Sets the volume for a specific audio channel.
 */
int32_t goud_audio_set_channel_volume(struct GoudContextId context_id, uint8_t channel, float volume);

/**
 * Returns the current global audio volume.
 */
float goud_audio_get_global_volume(struct GoudContextId context_id);

/**
 * Returns the current volume for a specific audio channel.
 */
float goud_audio_get_channel_volume(struct GoudContextId context_id, uint8_t channel);

/**
 * Checks whether a specific player is currently playing audio.
 */
int32_t goud_audio_is_playing(struct GoudContextId context_id, uint64_t player_id);

/**
 * Returns the number of active audio players.
 */
int32_t goud_audio_active_count(struct GoudContextId context_id);

/**
 * Cleans up finished audio players.
 */
int32_t goud_audio_cleanup_finished(struct GoudContextId context_id);

/**
 * Plays audio from raw in-memory bytes on the default SFX channel.
 */
int64_t goud_audio_play(struct GoudContextId context_id, const uint8_t *asset_data, size_t asset_len);

/**
 * Plays audio on a specific channel.
 */
int64_t goud_audio_play_on_channel(struct GoudContextId context_id, const uint8_t *asset_data, size_t asset_len, uint8_t channel);

/**
 * Plays audio with full control over volume, speed, looping, and channel.
 */
int64_t goud_audio_play_with_settings(struct GoudContextId context_id, const uint8_t *asset_data, size_t asset_len, float volume, float speed, bool looping, uint8_t channel);

/**
 * Plays audio with spatial attenuation in 2D (`z = 0`).
 */
int64_t goud_audio_play_spatial(struct GoudContextId context_id, const uint8_t *asset_data, size_t asset_len, float source_x, float source_y, float listener_x, float listener_y, float max_distance, float rolloff);

/**
 * Plays audio with spatial attenuation in 3D.
 */
int64_t goud_audio_play_spatial_3d(struct GoudContextId context_id, const uint8_t *asset_data, size_t asset_len, float source_x, float source_y, float source_z, float listener_x, float listener_y, float listener_z, float max_distance, float rolloff);

/**
 * Updates attenuation for a playing spatial source in 2D (`z = 0`).
 */
int32_t goud_audio_update_spatial_volume(struct GoudContextId context_id, uint64_t player_id, float source_x, float source_y, float listener_x, float listener_y, float max_distance, float rolloff);

/**
 * Updates attenuation for a playing spatial source in 3D.
 */
int32_t goud_audio_update_spatial_volume_3d(struct GoudContextId context_id, uint64_t player_id, float source_x, float source_y, float source_z, float listener_x, float listener_y, float listener_z, float max_distance, float rolloff);

/**
 * Sets the spatial listener position in 2D (`z = 0`).
 */
int32_t goud_audio_set_listener_position(struct GoudContextId context_id, float x, float y);

/**
 * Sets the spatial listener position in 3D.
 */
int32_t goud_audio_set_listener_position_3d(struct GoudContextId context_id, float x, float y, float z);

/**
 * Sets (or starts tracking) a source position in 2D (`z = 0`).
 */
int32_t goud_audio_set_source_position(struct GoudContextId context_id, uint64_t player_id, float x, float y, float max_distance, float rolloff);

/**
 * Sets (or starts tracking) a source position in 3D.
 */
int32_t goud_audio_set_source_position_3d(struct GoudContextId context_id, uint64_t player_id, float x, float y, float z, float max_distance, float rolloff);

/**
 * Sets per-player volume.
 */
int32_t goud_audio_set_player_volume(struct GoudContextId context_id, uint64_t player_id, float volume);

/**
 * Sets per-player playback speed.
 */
int32_t goud_audio_set_player_speed(struct GoudContextId context_id, uint64_t player_id, float speed);

/**
 * Applies an immediate two-player crossfade mix in `[0, 1]`.
 */
int32_t goud_audio_crossfade(struct GoudContextId context_id, uint64_t from_player_id, uint64_t to_player_id, float mix);

/**
 * Starts a timed crossfade from an active sink to a newly played asset.
 */
int64_t goud_audio_crossfade_to(struct GoudContextId context_id, uint64_t from_player_id, const uint8_t *asset_data, size_t asset_len, float duration_sec, uint8_t channel);

/**
 * Starts additive mixing by layering a secondary asset on top of a primary sink.
 */
int64_t goud_audio_mix_with(struct GoudContextId context_id, uint64_t primary_player_id, const uint8_t *asset_data, size_t asset_len, float secondary_volume, uint8_t secondary_channel);

/**
 * Advances active timed crossfades.
 */
int32_t goud_audio_update_crossfades(struct GoudContextId context_id, float delta_sec);

/**
 * Returns the number of in-flight timed crossfades, or `-1` on failure.
 */
int32_t goud_audio_active_crossfade_count(struct GoudContextId context_id);

