/**
 * Creates a new transform builder with default values.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_new(void);

/**
 * Creates a new transform builder at a specific position.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_at_position(float x, float y);

/**
 * Sets the position on the builder.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_with_position(struct FfiTransform2DBuilder *builder, float x, float y);

/**
 * Sets the rotation (in radians) on the builder.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_with_rotation(struct FfiTransform2DBuilder *builder, float rotation);

/**
 * Sets the rotation (in degrees) on the builder.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_with_rotation_degrees(struct FfiTransform2DBuilder *builder, float degrees);

/**
 * Sets the scale on the builder.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_with_scale(struct FfiTransform2DBuilder *builder, float scale_x, float scale_y);

/**
 * Sets uniform scale on the builder.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_with_scale_uniform(struct FfiTransform2DBuilder *builder, float scale);

/**
 * Makes the builder's transform look at a target position.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_looking_at(struct FfiTransform2DBuilder *builder, float target_x, float target_y);

/**
 * Translates the builder's position.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_translate(struct FfiTransform2DBuilder *builder, float dx, float dy);

/**
 * Rotates the builder's transform.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_rotate(struct FfiTransform2DBuilder *builder, float angle);

/**
 * Multiplies the builder's scale.
 */
struct FfiTransform2DBuilder *goud_transform2d_builder_scale_by(struct FfiTransform2DBuilder *builder, float factor_x, float factor_y);

/**
 * Builds and consumes the transform builder, returning the final transform.
 */
struct FfiTransform2D goud_transform2d_builder_build(struct FfiTransform2DBuilder *builder);

/**
 * Frees a transform builder without building.
 */
void goud_transform2d_builder_free(struct FfiTransform2DBuilder *builder);

/**
 * Returns the forward direction vector (positive X axis after rotation).
 */
struct FfiVec2 goud_transform2d_forward(const struct FfiTransform2D *transform);

/**
 * Returns the right direction vector (positive Y axis after rotation).
 */
struct FfiVec2 goud_transform2d_right(const struct FfiTransform2D *transform);

/**
 * Returns the backward direction vector (negative X axis after rotation).
 */
struct FfiVec2 goud_transform2d_backward(const struct FfiTransform2D *transform);

/**
 * Returns the left direction vector (negative Y axis after rotation).
 */
struct FfiVec2 goud_transform2d_left(const struct FfiTransform2D *transform);

/**
 * Creates a default Transform2D at the origin with no rotation and unit scale.
 */
struct FfiTransform2D goud_transform2d_default(void);

/**
 * Creates a Transform2D at the specified position with default rotation and scale.
 */
struct FfiTransform2D goud_transform2d_from_position(float x, float y);

/**
 * Creates a Transform2D at the origin with the specified rotation.
 */
struct FfiTransform2D goud_transform2d_from_rotation(float rotation);

/**
 * Creates a Transform2D at the origin with the specified rotation in degrees.
 */
struct FfiTransform2D goud_transform2d_from_rotation_degrees(float degrees);

/**
 * Creates a Transform2D at the origin with the specified scale.
 */
struct FfiTransform2D goud_transform2d_from_scale(float scale_x, float scale_y);

/**
 * Creates a Transform2D with uniform scale.
 */
struct FfiTransform2D goud_transform2d_from_scale_uniform(float scale);

/**
 * Creates a Transform2D with position and rotation.
 */
struct FfiTransform2D goud_transform2d_from_position_rotation(float x, float y, float rotation);

/**
 * Creates a Transform2D with all components specified.
 */
struct FfiTransform2D goud_transform2d_new(float pos_x, float pos_y, float rotation, float scale_x, float scale_y);

/**
 * Creates a Transform2D looking at a target position.
 */
struct FfiTransform2D goud_transform2d_look_at(float pos_x, float pos_y, float target_x, float target_y);

/**
 * Computes the 3x3 transformation matrix.
 */
struct FfiMat3x3 goud_transform2d_matrix(const struct FfiTransform2D *transform);

/**
 * Computes the inverse transformation matrix.
 */
struct FfiMat3x3 goud_transform2d_matrix_inverse(const struct FfiTransform2D *transform);

/**
 * Transforms a point from local space to world space.
 */
struct FfiVec2 goud_transform2d_transform_point(const struct FfiTransform2D *transform, float point_x, float point_y);

/**
 * Transforms a direction from local space to world space.
 */
