/**
 * Translates the transform by the given offset in world space.
 */
void goud_transform2d_translate(struct FfiTransform2D *transform, float dx, float dy);

/**
 * Translates the transform in local space.
 */
void goud_transform2d_translate_local(struct FfiTransform2D *transform, float dx, float dy);

/**
 * Sets the position of the transform.
 */
void goud_transform2d_set_position(struct FfiTransform2D *transform, float x, float y);

/**
 * Gets the position of the transform.
 */
struct FfiVec2 goud_transform2d_get_position(const struct FfiTransform2D *transform);

/**
 * Rotates the transform by the given angle in radians.
 */
void goud_transform2d_rotate(struct FfiTransform2D *transform, float angle);

/**
 * Rotates the transform by the given angle in degrees.
 */
void goud_transform2d_rotate_degrees(struct FfiTransform2D *transform, float degrees);

/**
 * Sets the rotation angle in radians.
 */
void goud_transform2d_set_rotation(struct FfiTransform2D *transform, float rotation);

/**
 * Sets the rotation angle in degrees.
 */
void goud_transform2d_set_rotation_degrees(struct FfiTransform2D *transform, float degrees);

/**
 * Gets the rotation angle in radians.
 */
float goud_transform2d_get_rotation(const struct FfiTransform2D *transform);

/**
 * Gets the rotation angle in degrees.
 */
float goud_transform2d_get_rotation_degrees(const struct FfiTransform2D *transform);

/**
 * Makes the transform look at a target position.
 */
void goud_transform2d_look_at_target(struct FfiTransform2D *transform, float target_x, float target_y);

/**
 * Sets the scale of the transform.
 */
void goud_transform2d_set_scale(struct FfiTransform2D *transform, float scale_x, float scale_y);

/**
 * Sets uniform scale on both axes.
 */
void goud_transform2d_set_scale_uniform(struct FfiTransform2D *transform, float scale);

/**
 * Gets the scale of the transform.
 */
struct FfiVec2 goud_transform2d_get_scale(const struct FfiTransform2D *transform);

/**
 * Multiplies the current scale by the given factors.
 */
void goud_transform2d_scale_by(struct FfiTransform2D *transform, float factor_x, float factor_y);

